function DefaultCurrency9119() {}
DefaultCurrency9119.dataBinding = "/ds/EnterVariableData/curr1";
DefaultCurrency9119.tabIndex = -1;
DefaultCurrency9119.maxLength = 1;
DefaultCurrency9119.isReadOnly = function(){return true;}
DefaultCurrency9119.isTemporary = function(){return true;}
DefaultCurrency9119.transformToDisplay = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToDisplay(value,null,null); }
DefaultCurrency9119.transformToModel = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToModel(value,null,null); }
